def calc_user_similarity(user_items):
    """计算用户相似度矩阵"""
    C = defaultdict(lambda: defaultdict(int))
    N = defaultdict(int)

    for user, items in user_items.items():
        N[user] = len(items)
        for v in items:
            for u in items:
                if user == u:
                    continue
                C[user][u] += 1

    W = defaultdict(lambda: defaultdict(float))
    for u, related_users in C.items():
        for v, cuv in related_users.items():
            W[u][v] = cuv / math.sqrt(N[u] * N[v])

    return W, N

def user_cf_recommend(user, user_items, W, top_k=10):
    """基于用户协同过滤推荐"""
    rank = defaultdict(float)
    user_rated_items = user_items[user]

    for similar_user, w in sorted(W[user].items(), 
                                   key=lambda x: x[1], reverse=True)[:20]:
        for item, rating in user_items[similar_user].items():
            if item in user_rated_items:
                continue
            rank[item] += w * rating

    return sorted(rank.items(), key=lambda x: x[1], reverse=True)[:top_k]

# 计算用户相似度
user_sim, user_count = calc_user_similarity(user_items)

