from torch.utils.data import Dataset, DataLoader
import numpy as np

class MovieLensDataset(Dataset):
    def __init__(self, data, n_items, negative_samples=4):
        self.data = data
        self.n_items = n_items
        self.negative_samples = negative_samples
        self.user_items = {}
        for uid, iid, _ in data:
            if uid not in self.user_items:
                self.user_items[uid] = set()
            self.user_items[uid].add(iid)
        self.samples = self._generate_samples()

    def _generate_samples(self):
        samples = []
        for uid, iid, rating in self.data:
            samples.append((uid, iid, 1))
            # 负采样
            for _ in range(self.negative_samples):
                neg_iid = np.random.randint(1, self.n_items + 1)
                while neg_iid in self.user_items.get(uid, set()):
                    neg_iid = np.random.randint(1, self.n_items + 1)
                samples.append((uid, neg_iid, 0))
        return samples

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        uid, iid, label = self.samples[idx]
        return torch.LongTensor([uid]), torch.LongTensor([iid]), \
               torch.FloatTensor([label])
