class RecommendationService:
    def __init__(self):
        self.models = {}
        self.item_sim = None
        self.user_items = None
        self.movies = None

    def load_data(self, item_sim, user_items, movies):
        self.item_sim = item_sim
        self.user_items = user_items
        self.movies = movies

    def get_item_cf_rec(self, user_id, top_k=10):
        """基于物品协同过滤推荐"""
        if user_id not in self.user_items:
            return []

        rank = defaultdict(float)
        user_rated = self.user_items[user_id]

        for item, rating in user_rated.items():
            for related_item, w in sorted(
                self.item_sim.get(item, {}).items(), 
                key=lambda x: x[1], reverse=True
            )[:50]:
                if related_item in user_rated:
                    continue
                rank[related_item] += w * rating

        rec_items = sorted(rank.items(), key=lambda x: x[1], reverse=True)[:top_k]

        result = []
        for movie_id, score in rec_items:
            title = self.movies.get(movie_id, 'Unknown')
            result.append({
                'movie_id': movie_id,
                'title': title,
                'score': round(float(score), 4)
            })
        return result

    def get_similar_items(self, item_id, top_k=10):
        """相似物品推荐"""
        if item_id not in self.item_sim:
            return []

        similar = sorted(self.item_sim[item_id].items(), 
                        key=lambda x: x[1], reverse=True)[:top_k]

        result = []
        for sim_id, score in similar:
            title = self.movies.get(sim_id, 'Unknown')
            result.append({
                'movie_id': sim_id,
                'title': title,
                'similarity': round(float(score), 4)
            })
        return result

    def get_user_history(self, user_id):
        """获取用户历史评分记录"""
        if user_id not in self.user_items:
            return []

        history = []
        for movie_id, rating in self.user_items[user_id].items():
            title = self.movies.get(movie_id, 'Unknown')
            history.append({
                'movie_id': movie_id,
                'title': title,
                'rating': float(rating)
            })
        return sorted(history, key=lambda x: x['rating'], reverse=True)

# 初始化服务
